// Single slot layout: [value(160 bits) | length(48 bits) | key(48 bits)]
// If value >= address() sentinel, store value in not(slot) overflow slot
assembly {
    // Pack key + count + value into one slot
    if iszero(or(eq(newValue, address()), shr(160, newValue))) {
        sstore(checkpointSlot, or(or(key, shl(48, n)), shl(96, newValue)))
        break
